package com.games.controller;import com.games.dto.*;import com.games.dto.RiddleResponse;import com.games.entity.User;import com.games.service.GameService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.http.HttpStatus;import org.springframework.http.ResponseEntity;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.web.bind.annotation.*;@RestController@RequestMapping("/api/game")@RequiredArgsConstructorpublic class GameController {    private final GameService gameService;    /**     * GET /api/game/riddle?difficulty=EASY|MEDIUM|HARD     * Returns a random riddle (optionally filtered by difficulty).     */    @GetMapping("/riddle")    public ResponseEntity<RiddleResponse> getRandomRiddle(            @RequestParam(required = false) String difficulty) {        return ResponseEntity.ok(gameService.getRandomRiddle(difficulty));    }    /**     * GET /api/game/riddle/category?category=LOGIC|MATH|WORDPLAY|SCIENCE|GENERAL|RIDDLE     * Returns a random riddle filtered by category.     */    @GetMapping("/riddle/category")    public ResponseEntity<RiddleResponse> getRiddleByCategory(            @RequestParam String category) {        return ResponseEntity.ok(gameService.getRiddleByCategory(category));    }    /**     * POST /api/game/riddle/generate     * Forces AI to generate a new riddle, saves it to DB, returns it.     * Body: { "difficulty": "MEDIUM", "category": "LOGIC" }     */    @PostMapping("/riddle/generate")    public ResponseEntity<RiddleResponse> generateRiddle(            @RequestBody GenerateRiddleRequest request) {        return ResponseEntity.status(HttpStatus.CREATED)                .body(gameService.generateAndSaveRiddle(request));    }    /**     * POST /api/game/answer     * Submit an answer for a riddle. Answer is checked against DB (not AI).     * Body: { "riddleId": 1, "answer": "a map" }     */    @PostMapping("/answer")    public ResponseEntity<AnswerResponse> submitAnswer(            @AuthenticationPrincipal User user,            @Valid @RequestBody AnswerRequest request) {        return ResponseEntity.ok(gameService.submitAnswer(user, request));    }    /**     * GET /api/game/hint/{id}     * Returns stored DB hint + AI contextual hint with per-user chat memory.     */    @GetMapping("/hint/{id}")    public ResponseEntity<HintResponse> getHint(            @AuthenticationPrincipal User user,            @PathVariable Long id) {        return ResponseEntity.ok(gameService.getHint(user, id));    }}